var e=[{id:`L2_1`,type:`dialog`,speaker:`ESTAROSSA_ZODIAC_NEXT_NULL`,text:{KOREA:`나는 이미 그대와 기사로서 맹세했다. 하지만 이전과 달리 지금의 우리가 함께하는데 별다른 조건은 필요하지 않아.`,JPN:`私はすでに騎士として君に誓いを立てている。だが、以前とは違い、あえて契約を結ばずとも、今の私たちは互いのために生きている。`,ENG:`I've already made my vow with you as a knight. But unlike before, there's no longer any condition to our bond.`,TWN:`我已經以騎士身分向你立誓。但如今我們同行之路，已無需其他條件。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ESTAROSSA_ZODIAC_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`ESTAROSSA_ZODIAC_NEXT_NULL`,text:{KOREA:`그대가 신념을 지키는 한, 나는 기사로서 마지막까지 그대의 곁을 지키겠다.`,JPN:`君が信念を持ち続ける限り、私は騎士として最後まで君のそばに居よう。`,ENG:`As long as you stay true to your convictions, I will remain by your side until the very end.`,TWN:`只要你堅持信念，我便會作為騎士守護到最後一刻。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ESTAROSSA_ZODIAC_NEXT_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};